```c++
template<typename T>
inline T clip1 (T x, typename decomplexify<T>::type sat = typename decomplexify<T>::type(1)) {
  if (std::abs (x) > sat)
    return (x / std::abs(x)) * sat;
  else
    return x;
}

template<typename out_cont_t, typename in_cont_t, typename T>
inline out_cont_t clip (const in_cont_t& in, T sat) {
  out_cont_t out (boost::size (in));
  typename boost::range_const_iterator<in_cont_t>::type i = boost::begin (in);
  typename boost::range_const_iterator<in_cont_t>::type e = boost::end (in);
  typename boost::range_iterator<out_cont_t>::type o = boost::begin (out);
  for (; i != e; ++i, ++o)
    *o = clip1<typename boost::range_value<in_cont_t>::type> (*i, sat);

  return out;
}
...
