   <div class="Post-overview" id="{{Post.id}}">
       <div class="Post-overview-image"><img src="{{Post.image.url}}" height="128" width="128"></div>
       <div class="text">
           <div><span class="Post-overview-title">{{Post.title|escape}}</span></div>
           <div><span class="Post-overview-created">{{Post.created_at}}</span></div>
           <div><span class="Post-overview-description">{{Post.description|escape}}</span></div>
           <div><span class="Post-overview-tags">Теги: &nbsp;&nbsp;{% for item in Post.tags.all %}<a href="/?tags={{item.tag}}">{{item.tag|escape}}</a>{% endfor %}</span></div>
       </div>
   </div>
   <div class="Post-body">{{Post.body|escape|bbcode}}</div>
   <div class="Post-comments">
       {% if Post.comments.all %}<small style='text-align: right;'>Комментарии: {{Post.comments.all|length}}</small>{% endif %}
       {% if request.user.is_authenticated %}
           <form action="{% url 'comment_add' %}" method="POST" enctype="application/x-www-form-urlencoded">
           {% csrf_token %}
           <span id="comment-add-parent"></span>
           <input type="hidden" name="id" value="{{Post.id}}">
           <div><textarea id="comment-add-form" maxlength="250" name="text"></textarea></div>
           <div><input class="btn-send-comment" type="submit" value="Добавить комментарий"></div>
       </form>
       {% else %}
       <small>Для комментирования записей необходимо <a href="{% url 'login' %}?redirect={{request.build_absolute_uri|urlencode}}">авторизироваться</a></small>
       {% endif %}
       {% recursetree Post.comments.all %}
       <div class="comment" id="comment-{{node.id}}">
           <div class="comment-info">
               <span class="comment-author" id="comment-{{node.id}}-author"><a style="color:blue;" href="{% url 'user_profile' index=node.author.id %}">{{node.author|escape}}</a></span>
               <span class="comment-date" id="comment-{{node.id}}-date">{{node.pub_date}}</span>
           </div>
           <span class="comment-body">{{node.text|escape|bbcode}}</span>
           {% if node.get_ancestors.count < 4 %}<div><a class="btn-answer" href="#comment-add-form" onclick="answer('{{node.id}}','{{node.author}}','{{node.pub_date}}');"><small>Ответить</small></a></div>{% endif %}
           {% if not node.is_leaf_node %}
                <div class="comment-children">
                    {{ children }}
                </div>
            {% endif %}
       </div>
       {% endrecursetree %}
       {% if not Post.comments.all %}
           <span style="font-size: 15px;color: #708090;margin-left: 40%;margin-right: 40%;">Нет комментариев</span>
       {% endif %}
   </div>
{% endblock %}`

